describe('isValidEmail', () => {
  it('should accept valid email addresses', () => {
    expect(isValidEmail('user@example.com')).toBe(true);
    expect(isValidEmail('test.user+tag@domain.co.uk')).toBe(true);
  });

  it('should reject invalid email formats', () => {
    expect(isValidEmail('invalid')).toBe(false);
    expect(isValidEmail('no@domain')).toBe(false);
    expect(isValidEmail('@example.com')).toBe(false);
    expect(isValidEmail('user@')).toBe(false);
  });

  it('should reject emails with spaces', () => {
    expect(isValidEmail('user @example.com')).toBe(false);
    expect(isValidEmail('user@ example.com')).toBe(false);
  });
});

describe('sanitizeInput', () => {
  it('should escape HTML special characters', () => {
    expect(sanitizeInput('<script>alert("xss")</script>'))
      .toBe('&lt;script&gt;alert(&quot;xss&quot;)&lt;/script&gt;');
  });

  it('should escape all dangerous characters', () => {
    expect(sanitizeInput('<>')).toBe('&lt;&gt;');
    expect(sanitizeInput('"')).toBe('&quot;');
    expect(sanitizeInput("'")).toBe('&#039;');
  });

  it('should handle mixed content', () => {
    expect(sanitizeInput('Hello <b>World</b>'))
      .toBe('Hello &lt;b&gt;World&lt;/b&gt;');
  });

  it('should handle empty strings', () => {
    expect(sanitizeInput('')).toBe('');
  });

  it('should handle strings without special characters', () => {
    expect(sanitizeInput('Plain text')).toBe('Plain text');
  });
});

describe('createUser', () => {
  beforeEach(() => {
    // Mock saveUser to avoid database calls
    vi.mock('./clean-code', async () => {
      const actual = await vi.importActual('./clean-code');
      return {
        ...actual,
        saveUser: vi.fn().mockResolvedValue(undefined)
      };
    });
  });

  it('should create a valid user with sanitized input', async () => {
    const input = { email: 'TEST@EXAMPLE.COM', name: 'John <script>' };
    const user = await createUser(input);

    expect(user.email).toBe('test@example.com');
    expect(user.name).toBe('John &lt;script&gt;');
    expect(user.id).toMatch(/^user_\d+_[a-z0-9]+$/);
    expect(user.createdAt).toBeInstanceOf(Date);
  });

  it('should throw error when email is missing', async () => {
    await expect(createUser({ email: '', name: 'John' }))
      .rejects.toThrow('Email and name are required');
  });

  it('should throw error when name is missing', async () => {
    await expect(createUser({ email: 'test@example.com', name: '' }))
      .rejects.toThrow('Email and name are required');
  });

  it('should throw error for invalid email format', async () => {
    await expect(createUser({ email: 'invalid-email', name: 'John' }))
      .rejects.toThrow('Invalid email format');
  });

  it('should call saveUser with correct parameters', async () => {
    const input = { email: 'test@example.com', name: 'John' };
    await createUser(input);

    expect(saveUser).toHaveBeenCalledWith(
      expect.objectContaining({
        email: 'test@example.com',
        name: 'John'
      })
    );
  });
});

