describe('saveUser', () => {
  it('should use parameterized query to prevent SQL injection', async () => {
    const mockDb = { query: vi.fn().mockResolvedValue({}) };
    const user: User = {
      id: 'user_123',
      email: 'test@example.com',
      name: "Robert'); DROP TABLE users;--",
      createdAt: new Date('2024-01-01')
    };

    await saveUser(user);

    // Verify parameterized query is used
    expect(mockDb.query).toHaveBeenCalledWith(
      'INSERT INTO users (id, email, name, created_at) VALUES ($1, $2, $3, $4)',
      [user.id, user.email, user.name, user.createdAt]
    );
  });

  it('should handle database errors gracefully', async () => {
    const mockDb = { query: vi.fn().mockRejectedValue(new Error('DB connection failed')) };
    const user: User = {
      id: 'user_123',
      email: 'test@example.com',
      name: 'Test',
      createdAt: new Date()
    };

    await expect(saveUser(user)).rejects.toThrow('DB connection failed');
  });
});

describe('isValidEmail - edge cases', () => {
  it('should handle emails with plus addressing', () => {
    expect(isValidEmail('user+tag@example.com')).toBe(true);
  });

  it('should handle emails with subdomains', () => {
    expect(isValidEmail('user@mail.example.com')).toBe(true);
  });

  it('should handle emails with hyphens', () => {
    expect(isValidEmail('user@ex-ample.com')).toBe(true);
  });

  it('should reject multiple @ symbols', () => {
    expect(isValidEmail('user@@example.com')).toBe(false);
    expect(isValidEmail('user@ex@mple.com')).toBe(false);
  });

  it('should reject emails with consecutive dots', () => {
    expect(isValidEmail('user..name@example.com')).toBe(false);
  });
});

describe('sanitizeInput - security edge cases', () => {
  it('should handle multiple nested tags', () => {
    expect(sanitizeInput('<<script>>alert()</script>'))
      .toBe('&lt;&lt;script&gt;&gt;alert()&lt;/script&gt;');
  });

  it('should handle javascript protocol', () => {
    expect(sanitizeInput('javascript:alert("xss")'))
      .toBe('javascript:alert(&quot;xss&quot;)');
  });

  it('should handle event handlers', () => {
    expect(sanitizeInput('<img onerror="alert()">'))
      .toBe('&lt;img onerror=&quot;alert()&quot;&gt;');
  });

  it('should handle unicode and special characters', () => {
    expect(sanitizeInput('Test 测试 🎉')).toBe('Test 测试 🎉');
  });
});

